import {ROSTER,scaledStats,makeMon} from '../data/roster.js';import {MOVES,ADV} from '../data/moves.js';import {loadState,saveState} from '../systems/save.js';import {uiBox,hpBar,setVirtualHandler} from '../systems/ui.js';
const Phaser = window.Phaser;
const OPTS=['RECRUIT','SCOUT FURTHER','LEAVE'];
export class ScoutScene extends Phaser.Scene{
  constructor(){super('ScoutScene');}
  create(data={}){this.id=data.id||'buckshot';this.lvl=data.lvl||4;this.area=data.area||'campus';this.state=loadState();this.sel=0;this.note='';this.result='';this.tempInterest=Phaser.Math.Between(45,88);this.cameras.main.setBackgroundColor('#314451');this.input.keyboard.on('keydown-UP',()=>this.move(-1));this.input.keyboard.on('keydown-DOWN',()=>this.move(1));this.input.keyboard.on('keydown-ENTER',()=>this.choose());this.input.keyboard.on('keydown-SPACE',()=>this.choose());this.input.keyboard.on('keydown-ESC',()=>this.leave());setVirtualHandler(this);this.render();}
  potential(r){return {Common:'C+',Uncommon:'B',Rare:'A-',Elite:'A+'}[r.rarity]||'C';}
  odds(r){const base={Common:.50,Uncommon:.38,Rare:.24,Elite:.12}[r.rarity]||.34;const gr=Math.min(.22,(this.state.grit||0)*.01);const interest=(this.tempInterest||62)/500;const seen=this.state.dex?.seen?.[this.id]?.05:0;const film=(this.state.items?.film||0)>0?.04:0;return Math.max(.05,Math.min(.9,base+gr+interest+seen+film));}
  render(){this.children.removeAll();const r=ROSTER[this.id],s=scaledStats(this.id,this.lvl),od=Math.round(this.odds(r)*100);this.add.text(120,7,'SCOUT REPORT',{fontFamily:'monospace',fontSize:10,color:'#f8f0d8',fontStyle:'bold',stroke:'#111',strokeThickness:2}).setOrigin(.5);uiBox(this,8,19,224,142);const img=this.add.image(55,64,'battle_'+r.asset).setScale(.52);if(r.tint||r.color)img.setTint(r.tint||r.color);this.add.text(92,29,r.name,{fontFamily:'monospace',fontSize:9,color:'#111',fontStyle:'bold'});this.add.text(92,42,`${r.weight} lb  ${r.style}`,{fontFamily:'monospace',fontSize:7,color:'#333',fontStyle:'bold'});this.add.text(92,53,`Potential ${this.potential(r)}  OVR ${Math.round((s.hp+s.atk+s.def+s.spd+s.gas)/12)}  Lv ${this.lvl}`,{fontFamily:'monospace',fontSize:7,color:'#333'});hpBar(this,92,67,66,5,1,0x55b867);this.add.text(163,64,`HP ${s.hp}`,{fontFamily:'monospace',fontSize:6,color:'#333'});hpBar(this,92,79,66,4,1,0x5aa4e6);this.add.text(163,76,`EP ${s.gas}`,{fontFamily:'monospace',fontSize:6,color:'#333'});this.add.text(18,95,'TECHNIQUES',{fontFamily:'monospace',fontSize:7,color:'#b41820',fontStyle:'bold'});r.moves.slice(0,4).forEach((key,i)=>{const m=MOVES[key];this.add.text(20+(i%2)*103,108+(i>1?10:0),`• ${m.name}`,{fontFamily:'monospace',fontSize:6,color:'#111'});});this.add.text(18,129,`+ ${r.strengths||'Balanced'}  - ${r.weaknesses||'Unknown'}  ${r.personality||'Focused'}`,{fontFamily:'monospace',fontSize:5,color:'#333',wordWrap:{width:205}});this.add.text(18,137,`Interest ${this.tempInterest}%   Style edge: ${this.tip(r.style)}   Odds ${od}%`,{fontFamily:'monospace',fontSize:5,color:'#333'});OPTS.forEach((o,i)=>this.add.text(17+i*74,148,`${i===this.sel?'▶':''}${o}`,{fontFamily:'monospace',fontSize:6,color:i===this.sel?'#b41820':'#111',fontStyle:'bold'}));if(this.note)this.add.text(120,156,this.note,{fontFamily:'monospace',fontSize:6,color:'#111',fontStyle:'bold'}).setOrigin(.5);}
  tip(style){const a=Object.keys(ADV).find(k=>ADV[k]===style);return `${a||'Neutral'} attacks`;} 
  move(d){this.sel=Phaser.Math.Wrap(this.sel+d,0,OPTS.length);this.note='';this.render();}
  choose(){if(this.sel===0)return this.tryRecruit();if(this.sel===1)return this.battle();this.leave();}
  battle(){this.state.dex.seen[this.id]=true;this.state.stats.scouts=(this.state.stats.scouts||0)+1;saveState(this.state);this.scene.start('BattleScene',{enemyId:this.id,enemyLevel:this.lvl,battleType:'wild'});}
  tryRecruit(){const r=ROSTER[this.id];this.state.dex.seen[this.id]=true;if(this.state.dex.caught[this.id]){this.note='Already on roster.';return this.render();}if((this.state.items.invite||0)<=0){this.note='No invites left.';return this.render();}this.state.items.invite--;const success=Math.random()<this.odds(r);if(success){const m=makeMon(this.id,this.lvl);this.state.dex.caught[this.id]=true;if(this.state.party.length<6)this.state.party.push(m);else this.state.box.push(m);this.state.stats.recruits=(this.state.stats.recruits||0)+1;this.state.message=`${r.name} joined the room!`;if((Object.keys(this.state.dex.caught||{}).filter(k=>this.state.dex.caught[k]).length)>=2){this.state.objective={id:'first_recruit_done',stage:2,complete:true};}saveState(this.state);this.obtainAnim(`${r.name} joined!`);}else{this.state.message=`${r.name} wants to see more.`;saveState(this.state);this.note='Recruit passed. Try battle.';this.render();}}
  obtainAnim(msg){this.children.removeAll();this.cameras.main.flash(160,255,255,255);uiBox(this,18,52,204,62);this.add.text(120,65,'RECRUIT OBTAINED',{fontFamily:'monospace',fontSize:10,color:'#b41820',fontStyle:'bold'}).setOrigin(.5);this.add.text(120,84,msg,{fontFamily:'monospace',fontSize:8,color:'#111',align:'center',wordWrap:{width:174}}).setOrigin(.5);this.add.text(120,105,'A CONTINUE',{fontFamily:'monospace',fontSize:7,color:'#555',fontStyle:'bold'}).setOrigin(.5);this.input.keyboard.once('keydown-ENTER',()=>this.leave());this.input.keyboard.once('keydown-SPACE',()=>this.leave());this.sel=2;}
  leave(){this.scene.start('OverworldScene');}
  handleVirtualButton(k){if(k==='up')this.move(-1);if(k==='down')this.move(1);if(k==='a')this.choose();if(k==='b')this.leave();}
}
